// Create a flat list of all disabilities for searching
export const allVADisabilities = vaDisabilitiesBySystem.flatMap(system => 
  system.conditions.map(condition => ({
    ...condition,
    bodySystem: system.name,
    codeRange: system.codeRange
  }))
);

// Get total count
export const totalDisabilitiesCount = allVADisabilities.length;
